"use client";

import type { MouseEvent, ReactNode } from "react";
import { hasFirebaseIdTokenCookie } from "@/lib/firebase/client-session";
import { buildSignInPath, sanitizeNextPath } from "@/lib/routing";
import { continueToProtectedPathWithGoogleSignIn } from "@/lib/firebase/google-sign-in";
import { logClientError, logClientInfo } from "@/lib/logging/client";

type ProtectedRouteLinkProps = {
  children: ReactNode;
  className?: string;
  href: string;
};

function shouldBypassClickInterception(event: MouseEvent<HTMLAnchorElement>) {
  return (
    event.defaultPrevented ||
    event.button !== 0 ||
    event.metaKey ||
    event.ctrlKey ||
    event.shiftKey ||
    event.altKey
  );
}

export function ProtectedRouteLink({
  children,
  className,
  href,
}: ProtectedRouteLinkProps) {
  return (
    <a
      className={className}
      href={href}
      onClick={(event) => {
        if (shouldBypassClickInterception(event)) {
          return;
        }

        event.preventDefault();
        const nextPath = sanitizeNextPath(href);
        logClientInfo("auth", "protected_link_clicked", {
          nextPath,
        });

        if (hasFirebaseIdTokenCookie()) {
          logClientInfo("auth", "protected_link_cookie_present", {
            nextPath,
          });
          window.location.assign(nextPath);
          return;
        }

        void continueToProtectedPathWithGoogleSignIn(nextPath).catch((error) => {
          logClientError("auth", "protected_link_fallback_to_signin", error, {
            nextPath,
          });
          window.location.assign(buildSignInPath(nextPath));
        });
      }}
    >
      {children}
    </a>
  );
}
